const calculator = {
  // Base BTU per sqft for each climate zone (approx Manual J)
  CLIMATE_ZONE_BASE: {
    hot_dry: 35,
    hot_humid: 30,
    mixed: 25,
    cold: 20,
    very_cold: 15
  },

  // Insulation level multipliers
  INSULATION_MULTIPLIERS: {
    poor: 1.3,
    average: 1.0,
    good: 0.85,
    excellent: 0.7
  },

  validate(inputs) {
    const errors = [];

    // homeSqft
    if (inputs.homeSqft === undefined || inputs.homeSqft === null || inputs.homeSqft === '') {
      errors.push('Home square footage is required');
    } else {
      const sqftNum = Number(inputs.homeSqft);
      if (isNaN(sqftNum)) errors.push('Home square footage must be a number');
      else if (sqftNum <= 0) errors.push('Home square footage must be positive');
    }

    // climateZone
    const cz = String(inputs.climateZone || '').toLowerCase().trim();
    if (!cz) {
      errors.push('Climate zone is required');
    } else if (!['hot_dry','hot_humid','mixed','cold','very_cold'].includes(cz)) {
      errors.push('Invalid climate zone');
    }

    // insulationLevel
    const il = String(inputs.insulationLevel || '').toLowerCase().trim();
    if (!il) {
      errors.push('Insulation level is required');
    } else if (!['poor','average','good','excellent'].includes(il)) {
      errors.push('Invalid insulation level');
    }

    // ceilingHeight (default 8)
    if (inputs.ceilingHeight !== undefined && inputs.ceilingHeight !== null && inputs.ceilingHeight !== '') {
      const ceilNum = Number(inputs.ceilingHeight);
      if (isNaN(ceilNum)) errors.push('Ceiling height must be a number');
      else if (ceilNum <= 0) errors.push('Ceiling height must be positive');
    }

    return errors.length ? errors : null;
  },

  calculate(inputs) {
    // Validate first
    const validationErrors = this.validate(inputs);
    if (validationErrors) {
      return { error: validationErrors[0] }; // return first error
    }

    // Normalize inputs
    const homeSqft = Number(inputs.homeSqft);
    const climateZone = String(inputs.climateZone).toLowerCase().trim();
    const insulationLevel = String(inputs.insulationLevel).toLowerCase().trim();
    const ceilingHeight = (inputs.ceilingHeight !== undefined && inputs.ceilingHeight !== null && inputs.ceilingHeight !== '')
      ? Number(inputs.ceilingHeight)
      : 8; // default

    // Ceiling height multiplier (area adjustment)
    const ceilingMultiplier = ceilingHeight / 8;
    const adjustedSqft = homeSqft * ceilingMultiplier;

    const climateBase = this.CLIMATE_ZONE_BASE[climateZone];
    const insulationMult = this.INSULATION_MULTIPLIERS[insulationLevel];

    const totalBTU = adjustedSqft * climateBase * insulationMult;
    const totalTons = totalBTU / 12000;

    return {
      totalBTU,
      totalTons,
      breakdown: {
        adjustedSqft,
        climateZoneBaseBTU: climateBase,
        insulationMultiplier: insulationMult,
        ceilingMultiplier
      }
    };
  },

  formatCurrency(amount) {
    return '$' + amount.toFixed(2);
  }
};

const CALC_PARAMS = [
  {
    name: 'homeSqft',
    label: 'Home Square Footage',
    type: 'number',
    placeholder: 'e.g. 1500'
  },
  {
    name: 'climateZone',
    label: 'Climate Zone',
    type: 'select',
    options: [
      ['hot_dry', '🔥 Hot Dry'],
      ['hot_humid', '💧 Hot Humid'],
      ['mixed', '🌤️ Mixed'],
      ['cold', '❄️ Cold'],
      ['very_cold', '⛄ Very Cold']
    ]
  },
  {
    name: 'insulationLevel',
    label: 'Insulation Level',
    type: 'select',
    options: [
      ['poor', '⚠️ Poor'],
      ['average', '📉 Average'],
      ['good', '📈 Good'],
      ['excellent', '✅ Excellent']
    ]
  },
  {
    name: 'ceilingHeight',
    label: 'Ceiling Height (ft)',
    type: 'number',
    placeholder: 'default 8',
    defaultValue: 8
  }
];

// Export for module usage (if needed)
if (typeof module !== 'undefined' && module.exports) {
  module.exports = { calculator, CALC_PARAMS };
}
